// Improved application with security best practices
// Addresses: error handling, input validation, and security hardening

const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const validator = require('validator');
const app = express();

// ============================================================================
// SECURITY MIDDLEWARE
// ============================================================================

// 1. Set security headers
app.use(helmet());

// 2. Limit body size to prevent DoS
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ limit: '10kb', extended: true }));

// 3. Rate limiting to prevent brute force attacks
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later.',
  standardHeaders: true, // Return rate limit info in the `RateLimit-*` headers
  legacyHeaders: false, // Disable the `X-RateLimit-*` headers
});

const apiLimiter = rateLimit({
  windowMs: 1 * 60 * 1000, // 1 minute
  max: 30, // stricter limit for API endpoints
  skipSuccessfulRequests: true, // don't count successful requests
});

app.use(limiter);

// 4. Request validation middleware
const validateQuery = (schema) => (req, res, next) => {
  const errors = {};

  for (const [key, rules] of Object.entries(schema)) {
    const value = req.query[key];

    if (rules.required && !value) {
      errors[key] = `${key} is required`;
      continue;
    }

    if (value) {
      if (rules.type === 'number' && isNaN(value)) {
        errors[key] = `${key} must be a number`;
      }
      if (rules.type === 'string' && typeof value !== 'string') {
        errors[key] = `${key} must be a string`;
      }
      if (rules.maxLength && value.length > rules.maxLength) {
        errors[key] = `${key} must not exceed ${rules.maxLength} characters`;
      }
    }
  }

  if (Object.keys(errors).length > 0) {
    return res.status(400).json({
      error: 'Validation failed',
      details: errors
    });
  }

  next();
};

// ============================================================================
// ERROR HANDLING MIDDLEWARE (defined before routes)
// ============================================================================

// Request logging middleware
app.use((req, res, next) => {
  console.log(`[${new Date().toISOString()}] ${req.method} ${req.path}`);
  next();
});

// ============================================================================
// ROUTES WITH ERROR HANDLING
// ============================================================================

// Health check endpoint - minimal data exposure
app.get('/health', (req, res, next) => {
  try {
    res.json({
      status: 'ok',
      timestamp: new Date().toISOString()
    });
  } catch (error) {
    next(error);
  }
});

// Users endpoint with input validation and access control
app.get('/users', apiLimiter, validateQuery({
  id: { type: 'number', required: false },
  limit: { type: 'number', required: false },
}), (req, res, next) => {
  try {
    // Input validation
    const userId = req.query.id ? parseInt(req.query.id, 10) : null;
    const limit = req.query.limit ? Math.min(parseInt(req.query.limit, 10), 100) : 100;

    // Sanitize limit parameter
    if (isNaN(limit) || limit < 1 || limit > 100) {
      return res.status(400).json({
        error: 'Invalid limit parameter. Must be between 1 and 100.'
      });
    }

    // Mock user database (in production, use a real database with parameterized queries)
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Filter by ID if provided
    let result = users;
    if (userId) {
      // Validate ID is in safe range
      if (!Number.isInteger(userId) || userId < 0) {
        return res.status(400).json({
          error: 'Invalid user ID. Must be a positive integer.'
        });
      }
      result = users.filter(u => u.id === userId);

      if (result.length === 0) {
        return res.status(404).json({
          error: 'User not found'
        });
      }
    }

    // Apply limit
    result = result.slice(0, limit);

    // Security: Consider removing email in production or adding access control
    res.json({
      data: result,
      count: result.length,
      timestamp: new Date().toISOString()
    });

  } catch (error) {
    next(error);
  }
});

// ============================================================================
// GLOBAL ERROR HANDLER (must be last)
// ============================================================================

app.use((err, req, res, next) => {
  // Log error details for debugging (don't expose internals to client)
  console.error(`[ERROR] ${new Date().toISOString()}:`, {
    message: err.message,
    stack: process.env.NODE_ENV === 'development' ? err.stack : undefined,
    path: req.path,
    method: req.method
  });

  // Don't expose sensitive error details to client
  const statusCode = err.statusCode || 500;
  const message = statusCode === 500 ? 'Internal server error' : err.message;

  res.status(statusCode).json({
    error: message,
    requestId: req.id || 'unknown' // Add request ID for debugging
  });
});

// Handle 404 errors
app.use((req, res) => {
  res.status(404).json({
    error: 'Not found'
  });
});

// ============================================================================
// SERVER STARTUP
// ============================================================================

const PORT = process.env.PORT || 3000;
const HOST = process.env.HOST || 'localhost';

const server = app.listen(PORT, HOST, () => {
  console.log(`Server running on ${HOST}:${PORT}`);
});

// Graceful shutdown
process.on('SIGTERM', () => {
  console.log('SIGTERM signal received: closing HTTP server');
  server.close(() => {
    console.log('HTTP server closed');
    process.exit(0);
  });
});

module.exports = app;

# Security Review: app.js

## Executive Summary

The current `app.js` has significant security gaps in error handling, input validation, and general security hardening. This review provides recommendations and an improved implementation.

---

## 🔴 Critical Issues

### 1. **No Input Validation**
**Severity:** HIGH  
**Issue:** User endpoints accept any query parameters without validation
```javascript
// VULNERABLE: No validation
app.get('/users', (req, res) => {
  // Direct use of req.query without checking
});
```

**Fix:**
- Validate and sanitize all inputs (query params, body, headers)
- Use a validation library like `joi`, `yup`, or `validator`
- Implement type checking and length limits
- Reject unexpected parameters

### 2. **No Error Handling**
**Severity:** HIGH  
**Issue:** Application crashes silently without error handlers
```javascript
// VULNERABLE: No try-catch or error middleware
app.get('/users', (req, res) => {
  res.json([...]); // If this throws, no handler catches it
});
```

**Fix:**
- Wrap all route handlers in try-catch blocks
- Implement global error handling middleware
- Log errors securely (don't expose internals to clients)
- Return generic error messages to clients

### 3. **No Authentication/Authorization**
**Severity:** HIGH  
**Issue:** `/users` endpoint is publicly accessible without checks
```javascript
// VULNERABLE: Anyone can access user data
app.get('/users', (req, res) => {
  // No auth check
});
```

**Fix:**
- Implement authentication (JWT, sessions, API keys)
- Add middleware to verify user identity
- Implement role-based access control (RBAC)
- Protect sensitive endpoints

---

## 🟡 Medium Priority Issues

### 4. **Missing Security Headers**
**Severity:** MEDIUM  
**Issue:** No helmet.js or manual security headers

**Fix:**
```javascript
const helmet = require('helmet');
app.use(helmet()); // Sets 15+ security headers
```

**Headers Added:**
- `X-Content-Type-Options: nosniff` - Prevent MIME type sniffing
- `X-Frame-Options: DENY` - Prevent clickjacking
- `X-XSS-Protection: 1; mode=block` - XSS protection
- `Strict-Transport-Security` - Force HTTPS

### 5. **No Rate Limiting**
**Severity:** MEDIUM  
**Issue:** Vulnerable to DoS attacks and brute force

**Fix:**
```javascript
const rateLimit = require('express-rate-limit');
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100
});
app.use(limiter);
```

### 6. **No Body Size Limits**
**Severity:** MEDIUM  
**Issue:** Can accept arbitrarily large payloads (DoS)

**Fix:**
```javascript
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ limit: '10kb', extended: true }));
```

### 7. **Data Exposure**
**Severity:** MEDIUM  
**Issue:** Returns email addresses without access control
```javascript
// VULNERABLE: Exposes PII
{ id: 1, name: 'Alice', email: 'alice@example.com' }
```

**Fix:**
- Implement authorization checks before returning data
- Redact sensitive fields for unauthorized users
- Add data masking/encryption where appropriate

### 8. **No CORS Configuration**
**Severity:** MEDIUM  
**Issue:** No CORS headers = vulnerable to cross-origin attacks or overly permissive

**Fix:**
```javascript
const cors = require('cors');
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS?.split(',') || ['http://localhost:3000'],
  credentials: true,
  methods: ['GET', 'POST'],
  maxAge: 3600
}));
```

---

## 🟢 Low Priority Issues

### 9. **No Logging/Monitoring**
**Issue:** Can't audit access or detect attacks

**Fix:**
- Add request logging middleware
- Log security events (failed auth, rate limit hits)
- Use structured logging (Winston, Bunyan)

### 10. **Hardcoded Configuration**
**Issue:** Port and settings hardcoded instead of environment-based

**Fix:**
```javascript
const PORT = process.env.PORT || 3000;
const HOST = process.env.HOST || 'localhost';
```

### 11. **No Graceful Shutdown**
**Issue:** Server doesn't close connections cleanly

**Fix:**
```javascript
process.on('SIGTERM', () => {
  server.close(() => process.exit(0));
});
```

### 12. **Missing Request ID Tracking**
**Issue:** Hard to trace errors through logs

**Fix:**
```javascript
const { v4: uuidv4 } = require('uuid');
app.use((req, res, next) => {
  req.id = uuidv4();
  next();
});
```

---

## Implementation Checklist

- [ ] Install security dependencies
  ```bash
  npm install helmet express-rate-limit validator
  npm install --save-dev jest supertest
  ```

- [ ] Add input validation to all endpoints
- [ ] Implement global error handler
- [ ] Add security headers (helmet.js)
- [ ] Configure rate limiting
- [ ] Add request logging
- [ ] Implement authentication/authorization
- [ ] Add CORS configuration
- [ ] Set body size limits
- [ ] Add unit and integration tests
- [ ] Enable HTTPS in production
- [ ] Add security monitoring/alerts

---

## Dependencies to Add

```json
{
  "dependencies": {
    "express": "^4.18.0",
    "helmet": "^7.0.0",
    "express-rate-limit": "^6.7.0",
    "validator": "^13.9.0",
    "cors": "^2.8.5"
  },
  "devDependencies": {
    "jest": "^29.0.0",
    "supertest": "^6.3.0"
  }
}
```

---

## Testing Security

Add tests to verify security measures:

```javascript
// tests/security.test.js
describe('Security Tests', () => {
  test('should enforce rate limiting', async () => {
    for (let i = 0; i < 101; i++) {
      await request(app).get('/users');
    }
    const response = await request(app).get('/users');
    expect(response.status).toBe(429); // Too Many Requests
  });

  test('should validate input parameters', async () => {
    const response = await request(app).get('/users?id=invalid');
    expect(response.status).toBe(400);
    expect(response.body.error).toBeDefined();
  });

  test('should reject oversized payloads', async () => {
    const largePayload = 'x'.repeat(11000); // > 10kb limit
    const response = await request(app).post('/api/data').send({ data: largePayload });
    expect(response.status).toBe(413); // Payload Too Large
  });

  test('should include security headers', async () => {
    const response = await request(app).get('/health');
    expect(response.headers['x-content-type-options']).toBe('nosniff');
    expect(response.headers['x-frame-options']).toBe('DENY');
  });
});
```

---

## Environment Configuration

Create `.env` file for configuration:

```env
# Server
PORT=3000
HOST=localhost
NODE_ENV=production

# Security
ALLOWED_ORIGINS=http://localhost:3000,https://app.example.com

# Database
DB_HOST=localhost
DB_USER=app_user
DB_PASS=secure_password

# Logging
LOG_LEVEL=info
```

---

## References

